  8→
  9→  return (
 10→    <nav class="pressy-navigation" aria-label="Chapter navigation">
 11→      <div class="pressy-nav-inner">
 12→        {prev ? (
 13→          <a href={prev.slug} class="pressy-nav-link pressy-nav-prev">
 14→            <span class="pressy-nav-direction">Previous</span>
 15→            <span class="pressy-nav-title">{prev.title}</span>
 16→          </a>
 17→        ) : (
 18→          <div class="pressy-nav-placeholder" />
 19→        )}
 20→
 21→        {next ? (
 22→          <a href={next.slug} class="pressy-nav-link pressy-nav-next">
 23→            <span class="pressy-nav-direction">Next</span>
 24→            <span class="pressy-nav-title">{next.title}</span>
 25→          </a>
 26→        ) : (
 27→          <div class="pressy-nav-placeholder" />
 28→        )}
 29→      </div>
 30→
 31→      <style>{`
 32→        .pressy-navigation {
 33→          border-top: 1px solid var(--color-border);
 34→          padding: 2rem 1.5rem;
 35→          margin-top: 3rem;
 36→        }
 37→
 38→        .pressy-nav-inner {
 39→          display: flex;
 40→          justify-content: space-between;
 41→          gap: 2rem;
 42→          max-width: 65ch;
 43→          margin: 0 auto;
 44→        }
 45→
 46→        .pressy-nav-link {
 47→          display: flex;
 48→          flex-direction: column;
 49→          gap: 0.25rem;
 50→          text-decoration: none;
 51→          padding: 1rem;
 52→          border-radius: 0.5rem;
 53→          transition: background 0.15s;
 54→          max-width: 45%;
 55→        }
 56→
 57→        .pressy-nav-link:hover {
 58→          background: var(--color-bg-subtle);
 59→        }
 60→
 61→        .pressy-nav-prev {
 62→          align-items: flex-start;
 63→        }
 64→
 65→        .pressy-nav-next {
 66→          align-items: flex-end;
 67→          text-align: right;
 68→        }
 69→
 70→        .pressy-nav-direction {
