 26→export function BookProgress({
 27→  chapters,
 28→  basePath,
 29→  bookSlug,
 30→  loadAllProgress,
 31→}: BookProgressProps) {
 32→  const [progressMap, setProgressMap] = useState<
 33→    Map<string, { page: number; totalPages: number }>
 34→  >(new Map())
 35→
 36→  useEffect(() => {
 37→    loadAllProgress().then((allProgress) => {
 38→      const chapterSlugs = new Set(chapters.map((ch) => ch.slug))
 39→      const map = new Map<string, { page: number; totalPages: number }>()
 40→      for (const p of allProgress) {
 41→        if (chapterSlugs.has(p.chapterSlug)) {
 42→          map.set(p.chapterSlug, { page: p.page, totalPages: p.totalPages })
 43→        }
 44→      }
 45→      setProgressMap(map)
 46→    })
 47→  }, [chapters, loadAllProgress])
 48→
 49→  // Calculate overall book progress based on word counts
 50→  const totalWords = chapters.reduce((sum, ch) => sum + (ch.wordCount || 0), 0)
 51→  let wordsRead = 0
 52→  let chaptersCompleted = 0
 53→  let chaptersStarted = 0
 54→
 55→  for (const ch of chapters) {
 56→    const progress = progressMap.get(ch.slug)
 57→    if (!progress) continue
 58→
 59→    const chapterWords = ch.wordCount || 0
 60→    if (progress.totalPages > 0 && progress.page >= progress.totalPages - 1) {
 61→      // Chapter completed
 62→      wordsRead += chapterWords
 63→      chaptersCompleted++
 64→      chaptersStarted++
 65→    } else if (progress.page > 0 && progress.totalPages > 0) {
 66→      // Chapter in progress — estimate words read from page proportion
 67→      wordsRead += (progress.page / progress.totalPages) * chapterWords
 68→      chaptersStarted++
 69→    }
 70→  }
 71→
 72→  const overallPercent = totalWords > 0 ? (wordsRead / totalWords) * 100 : 0
 73→  const hasAnyProgress = chaptersStarted > 0
 74→
 75→  return (
 76→    <div class="pressy-book-progress-section">
 77→      {hasAnyProgress && (
 78→        <div class="pressy-overall-progress">
