 81→              class="pressy-overall-progress-fill"
 82→              style={{ width: `${overallPercent}%` }}
 83→            />
 84→          </div>
 85→          <div class="pressy-overall-progress-text">
 86→            {Math.round(overallPercent)}% complete
 87→            <span class="pressy-overall-progress-detail">
 88→              {chaptersCompleted} of {chapters.length} chapters
 89→            </span>
 90→          </div>
 91→        </div>
 92→      )}
 93→
 94→      <nav class="pressy-chapter-list">
 95→        {chapters.map((ch) => {
 96→          const progress = progressMap.get(ch.slug)
 97→          const isCompleted =
