 99→            progress.totalPages > 0 &&
100→            progress.page >= progress.totalPages - 1
101→          const isStarted = progress && progress.page > 0 && !isCompleted
102→
103→          return (
104→            <a
105→              href={`${basePath}/books/${bookSlug}/${ch.slug}`}
106→              class={`pressy-chapter-link ${isCompleted ? 'pressy-chapter--completed' : ''} ${isStarted ? 'pressy-chapter--started' : ''}`}
107→            >
108→              <span class="pressy-chapter-order">{ch.order}.</span>
109→              <span class="pressy-chapter-title">{ch.title}</span>
110→              {isCompleted && (
111→                <span class="pressy-chapter-badge pressy-chapter-badge--done">
112→                  Done
113→                </span>
114→              )}
115→              {isStarted && progress && (
