 910→  // Calculate page count and set column-width to match viewport
 911→  const recalculatePages = useCallback(() => {
 912→    const article = articleRef.current;
 913→    const viewport = viewportRef.current;
 914→    if (!article || !viewport) return;
 915→
 916→    const viewportWidth = viewport.clientWidth;
 917→    if (viewportWidth === 0) return;
 918→
 919→    // Set column-width to viewport width so each column = one page
 920→    article.style.columnWidth = `${viewportWidth}px`;
 921→
 922→    // Force synchronous layout recalculation
 923→    void article.scrollWidth;
 924→
 925→    const total = Math.max(1, Math.round(article.scrollWidth / viewportWidth));
 926→    setTotalPages(total);
 927→
 928→    // Clamp current page if now out of bounds (e.g. after resize)
 929→    setCurrentPage((prev) => Math.min(prev, total - 1));
 930→
 931→    // Update chapter ranges for multi-chapter mode
 932→    updateChapterRanges();
 933→  }, [updateChapterRanges]);
 934→
 935→  // Font size change handler (defined after recalculatePages)
 936→  const handleFontSizeChange = useCallback(
 937→    (delta: number) => {
 938→      setFontScale((prev) => {
 939→        const next =
 940→          Math.round(Math.max(0.8, Math.min(1.5, prev + delta)) * 10) / 10;
 941→        localStorage.setItem("pressy-font-size", String(next));
 942→        applyFontScale(next);
 943→        setTimeout(() => recalculatePages(), 100);
 944→        return next;
 945→      });
 946→    },
 947→    [applyFontScale, recalculatePages]
 948→  );
 949→
 950→  // Recalculate on mount and on resize via ResizeObserver
 951→  useEffect(() => {
 952→    const viewport = viewportRef.current;
 953→    if (!viewport) return;
 954→
 955→    // Delay initial calculation to let fonts and content render
 956→    const initialTimer = setTimeout(recalculatePages, 50);
 957→
 958→    const observer = new ResizeObserver(() => {
 959→      recalculatePages();
 960→    });
 961→    observer.observe(viewport);
 962→
 963→    return () => {
 964→      clearTimeout(initialTimer);
 965→      observer.disconnect();
 966→    };
 967→  }, [recalculatePages]);
 968→
 969→  // Recalculate when loaded chapters change
 970→  useEffect(() => {
 971→    if (loadedChapters.length > 0) {
 972→      // Delay to let new content render
 973→      const timer = setTimeout(recalculatePages, 50);
 974→      return () => clearTimeout(timer);
 975→    }
 976→  }, [loadedChapters.length, recalculatePages]);
 977→
 978→  // Recalculate when images finish loading
 979→  useEffect(() => {
 980→    const article = articleRef.current;
 981→    if (!article) return;
 982→
 983→    const images = article.querySelectorAll("img");
 984→    if (images.length === 0) return;
 985→
 986→    const onLoad = () => recalculatePages();
 987→    images.forEach((img) => {
 988→      if (!img.complete) {
 989→        img.addEventListener("load", onLoad);
 990→        img.addEventListener("error", onLoad);
 991→      }
 992→    });
 993→
 994→    return () => {
 995→      images.forEach((img) => {
 996→        img.removeEventListener("load", onLoad);
 997→        img.removeEventListener("error", onLoad);
 998→      });
 999→    };
1000→  }, [recalculatePages, loadedChapters.length]);
1001→
1002→  // Check ?page=last query param for backward navigation
1003→  useEffect(() => {
1004→    const params = new URLSearchParams(window.location.search);
1005→    if (params.get("page") === "last" && totalPages > 1) {
1006→      setCurrentPage(totalPages - 1);
1007→      hasRestoredRef.current = true;
1008→      // Clean up the URL
1009→      const url = new URL(window.location.href);
1010→      url.searchParams.delete("page");
1011→      history.replaceState(null, "", url.pathname);
1012→    }
1013→  }, [totalPages]);
1014→
1015→  // Restore saved page position after pagination is computed
1016→  useEffect(() => {
1017→    if (hasRestoredRef.current || totalPages <= 1 || !onRestoreProgress) return;
1018→
1019→    onRestoreProgress().then((data) => {
1020→      if (!data || data.page <= 0) {
1021→        hasRestoredRef.current = true;
1022→        return;
1023→      }
1024→
1025→      let targetPage: number;
1026→      if (data.totalPages === totalPages) {
1027→        // Same pagination layout — restore exact page
1028→        targetPage = data.page;
1029→      } else if (data.totalPages > 0) {
1030→        // Viewport changed — scale proportionally
1031→        const fraction = data.page / (data.totalPages - 1);
1032→        targetPage = Math.round(fraction * (totalPages - 1));
1033→      } else {
1034→        hasRestoredRef.current = true;
1035→        return;
1036→      }
1037→
1038→      const clamped = Math.max(0, Math.min(targetPage, totalPages - 1));
1039→      setCurrentPage(clamped);
