import { signal } from '@preact/signals'

const CACHED_BOOKS_KEY = 'pressy-cached-books'

export const offlineStatus = signal<'online' | 'offline'>('online')
export const cacheProgress = signal<{ bookSlug: string; current: number; total: number } | null>(null)
export const swReady = signal<boolean>(false)
export const installPrompt = signal<Event | null>(null)

// Restore cached books from localStorage synchronously on load
function loadCachedBooks(): Set<string> {
  if (typeof localStorage === 'undefined') return new Set()
  try {
    const stored = localStorage.getItem(CACHED_BOOKS_KEY)
    if (stored) return new Set(JSON.parse(stored))
  } catch {}
  return new Set()
}

export const cachedBooks = signal<Set<string>>(loadCachedBooks())

// Initialize offline detection
if (typeof window !== 'undefined') {
  offlineStatus.value = navigator.onLine ? 'online' : 'offline'

  window.addEventListener('online', () => {
    offlineStatus.value = 'online'
  })

  window.addEventListener('offline', () => {
    offlineStatus.value = 'offline'
  })
}

// PWA install prompt
export function setupInstallPrompt(): void {
  window.addEventListener('beforeinstallprompt', (e) => {
    e.preventDefault()
    installPrompt.value = e
  })
  window.addEventListener('appinstalled', () => {
    installPrompt.value = null
  })
}

export async function triggerInstall(): Promise<boolean> {
  const prompt = installPrompt.value as any
  if (!prompt) return false
  prompt.prompt()
  const { outcome } = await prompt.userChoice
  installPrompt.value = null
  return outcome === 'accepted'
}

// Service Worker registration
export async function registerServiceWorker(basePath = ''): Promise<ServiceWorkerRegistration | null> {
  if (!('serviceWorker' in navigator)) {
    console.warn('Service workers are not supported')
    return null
  }

  const swUrl = basePath ? `${basePath}/sw.js` : '/sw.js'
  const scope = basePath ? `${basePath}/` : '/'

  try {
    const registration = await navigator.serviceWorker.register(swUrl, {
      scope,
    })

    // Listen for messages from service worker
    navigator.serviceWorker.addEventListener('message', handleSWMessage)

    // Mark SW as ready when controller is available
    if (navigator.serviceWorker.controller) {
      swReady.value = true
    } else {
      navigator.serviceWorker.addEventListener('controllerchange', () => {
        swReady.value = true
      })
    }

    // Handle updates
    registration.addEventListener('updatefound', () => {
      const newWorker = registration.installing
      if (!newWorker) return

      newWorker.addEventListener('statechange', () => {
        if (newWorker.state === 'activated') {
          swReady.value = true
        }
      })
    })

    return registration
  } catch (err) {
    console.error('Service worker registration failed:', err)
    return null
  }
}

function persistCachedBooks() {
  try {
    localStorage.setItem(CACHED_BOOKS_KEY, JSON.stringify([...cachedBooks.value]))
  } catch {}
}

function handleSWMessage(event: MessageEvent) {
  const { type } = event.data

  if (type === 'CACHE_PROGRESS') {
    const { bookSlug, current, total } = event.data
    cacheProgress.value = { bookSlug, current, total }
  }

  if (type === 'CACHE_COMPLETE') {
    const { bookSlug } = event.data
    cacheProgress.value = null
    const newCached = new Set(cachedBooks.value)
    newCached.add(bookSlug)
    cachedBooks.value = newCached
    persistCachedBooks()
  }

  if (type === 'CACHE_STATUS') {
    const { cached } = event.data as { cached: string[] }
    const newCached = new Set<string>()
    for (const url of cached) {
      const match = url.match(/\/books\/([^/]+)/)
      if (match) {
        newCached.add(match[1])
      }
    }
    cachedBooks.value = newCached
    persistCachedBooks()
  }

  if (type === 'CACHE_CLEARED') {
    const { bookSlug } = event.data
    const newCached = new Set(cachedBooks.value)
    newCached.delete(bookSlug)
    cachedBooks.value = newCached
    persistCachedBooks()
  }
}

// Download a book for offline reading
export async function downloadBookForOffline(
  bookSlug: string,
  chapterUrls: string[]
): Promise<boolean> {
  if (!('serviceWorker' in navigator) || !navigator.serviceWorker.controller) {
    console.warn('Service worker not available')
    return false
  }

  // Build full URLs
  const urls = chapterUrls.map((url) =>
    url.startsWith('http') ? url : `${window.location.origin}${url}`
  )

  cacheProgress.value = { bookSlug, current: 0, total: urls.length }

  // Optimistically persist to localStorage immediately so state survives refresh
  const newCached = new Set(cachedBooks.value)
  newCached.add(bookSlug)
  cachedBooks.value = newCached
  persistCachedBooks()

  // Send message to service worker
  navigator.serviceWorker.controller.postMessage({
    type: 'CACHE_BOOK',
    bookSlug,
    urls,
  })

  return true
}

// Check if a book is available offline
export function isBookCached(bookSlug: string): boolean {
  return cachedBooks.value.has(bookSlug)
}

// Get cache status for URLs
export async function checkCacheStatus(urls: string[]): Promise<void> {
  if (!('serviceWorker' in navigator) || !navigator.serviceWorker.controller) {
    return
  }

  navigator.serviceWorker.controller.postMessage({
    type: 'GET_CACHE_STATUS',
    urls: urls.map((url) =>
      url.startsWith('http') ? url : `${window.location.origin}${url}`
    ),
  })
}

// Clear cached book
export async function clearBookCache(bookSlug: string): Promise<boolean> {
  // Update state and persist immediately
  const newCached = new Set(cachedBooks.value)
  newCached.delete(bookSlug)
  cachedBooks.value = newCached
  persistCachedBooks()

  if (!('serviceWorker' in navigator) || !navigator.serviceWorker.controller) {
    // Fallback to direct cache API
    try {
      const cache = await caches.open('pressy-offline-books')
      const keys = await cache.keys()

      for (const request of keys) {
        if (request.url.includes(`/books/${bookSlug}`)) {
          await cache.delete(request)
        }
      }

      return true
    } catch (err) {
      console.error('Failed to clear cache:', err)
      return false
    }
  }

  // Prefer message-based approach so SW can coordinate
  navigator.serviceWorker.controller.postMessage({
    type: 'CLEAR_BOOK_CACHE',
    bookSlug,
  })
  return true
}

/// <reference lib="webworker" />
import { precacheAndRoute, cleanupOutdatedCaches } from 'workbox-precaching'
import { registerRoute, NavigationRoute, Route } from 'workbox-routing'
import { NetworkFirst, CacheFirst, StaleWhileRevalidate } from 'workbox-strategies'
import { ExpirationPlugin } from 'workbox-expiration'

declare const self: ServiceWorkerGlobalScope

const OFFLINE_CACHE = 'pressy-offline'
// Use the SW's own location to derive the base path for offline.html,
// so it works on subpath deployments (e.g. /pressy/pr-preview/pr-1/sw.js)
const SW_BASE = new URL('./', (self as unknown as ServiceWorkerGlobalScope).location.href).pathname
const OFFLINE_URL = `${SW_BASE}offline.html`
const BOOK_CACHE = 'pressy-offline-books'

// Precache all static assets (injected by build tool)
precacheAndRoute(self.__WB_MANIFEST)

// Clean up old caches
cleanupOutdatedCaches()

// Cache the offline fallback page on install
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(OFFLINE_CACHE).then((cache) => cache.add(OFFLINE_URL))
  )
  self.skipWaiting()
})

self.addEventListener('activate', (event) => {
  event.waitUntil(self.clients.claim())
})

// Navigation: NetworkFirst with offline fallback
const navigationHandler = new NetworkFirst({
  cacheName: 'pressy-pages',
  networkTimeoutSeconds: 3,
})

registerRoute(
  new NavigationRoute(async (params) => {
    try {
      return await navigationHandler.handle(params)
    } catch {
      // Network failed and not in cache — serve offline fallback
      const cache = await caches.open(OFFLINE_CACHE)
      const fallback = await cache.match(OFFLINE_URL)
      return fallback || Response.error()
    }
  })
)

// Offline-cached book chapters: try the book cache first,
// then fall through to the normal navigation handler
registerRoute(
  new Route(
    ({ request, url }) =>
      request.mode === 'navigate' && url.pathname.match(/^\/books\/[^/]+\/[^/]+/),
    async (params) => {
      // Check offline book cache first
      const bookCache = await caches.open(BOOK_CACHE)
      const cached = await bookCache.match(params.request)
      if (cached) return cached

      // Fall through to network
      try {
        return await navigationHandler.handle(params)
      } catch {
        const cache = await caches.open(OFFLINE_CACHE)
        const fallback = await cache.match(OFFLINE_URL)
        return fallback || Response.error()
      }
    }
  )
)

// Cache images with CacheFirst strategy (exclude PWA icons — they're
// updated on each deploy and should not be stuck behind a stale cache)
registerRoute(
  ({ request, url }) =>
    request.destination === 'image' &&
    !url.pathname.endsWith('/icon-192.png') &&
    !url.pathname.endsWith('/icon-512.png') &&
    !url.pathname.endsWith('/favicon.png'),
  new CacheFirst({
    cacheName: 'pressy-images',
    plugins: [
      new ExpirationPlugin({
        maxEntries: 100,
        maxAgeSeconds: 60 * 60 * 24 * 30, // 30 days
      }),
    ],
  })
)

// Cache fonts with CacheFirst strategy
registerRoute(
  ({ request }) => request.destination === 'font',
  new CacheFirst({
    cacheName: 'pressy-fonts',
    plugins: [
      new ExpirationPlugin({
        maxEntries: 20,
        maxAgeSeconds: 60 * 60 * 24 * 365, // 1 year
      }),
    ],
  })
)

// Cache CSS and JS with NetworkFirst so deploys are picked up immediately.
// Vite hashes filenames so old URLs are never re-requested — the main
// benefit of caching here is offline support, not speed.
registerRoute(
  ({ request }) =>
    request.destination === 'style' || request.destination === 'script',
  new NetworkFirst({
    cacheName: 'pressy-static',
    networkTimeoutSeconds: 3,
  })
)

// Message handler for manual cache operations
self.addEventListener('message', async (event) => {
  if (event.data?.type === 'CACHE_BOOK') {
    const { bookSlug, urls } = event.data
    const cache = await caches.open(BOOK_CACHE)
    let completed = 0

    for (const url of urls) {
      try {
        const response = await fetch(url)
        if (response.ok) {
          await cache.put(url, response)
        }
      } catch (err) {
        console.error(`Failed to cache ${url}:`, err)
      }

      completed++
      // Report progress back to client
      event.source?.postMessage({
        type: 'CACHE_PROGRESS',
        bookSlug,
        current: completed,
        total: urls.length,
      })
    }

    // Notify client that caching is complete
    event.source?.postMessage({ type: 'CACHE_COMPLETE', bookSlug, urls })
  }

  if (event.data?.type === 'GET_CACHE_STATUS') {
    const { urls } = event.data
    const cache = await caches.open(BOOK_CACHE)
    const cached: string[] = []

    for (const url of urls) {
      const response = await cache.match(url)
      if (response) {
        cached.push(url)
      }
    }

    event.source?.postMessage({ type: 'CACHE_STATUS', cached })
  }

  if (event.data?.type === 'CLEAR_BOOK_CACHE') {
    const { bookSlug } = event.data
    const cache = await caches.open(BOOK_CACHE)
    const keys = await cache.keys()

    for (const request of keys) {
      if (request.url.includes(`/books/${bookSlug}`)) {
        await cache.delete(request)
      }
    }

    event.source?.postMessage({ type: 'CACHE_CLEARED', bookSlug })
  }

  if (event.data?.type === 'SKIP_WAITING') {
    self.skipWaiting()
  }
})

