const viewportWidth =
  viewportRef.current?.clientWidth || window.innerWidth;
// Chapter nav threshold: 30% of viewport for the linear-slide boundaries,
// 80px for the rubber-band boundaries (no chapter in that direction)
const chapterSlideThreshold = viewportWidth * 0.3;
const chapterRubberThreshold = 80;

const atStart = currentPage === 0;
